VALUES
  ('social-worker-moex-03211', 'social-worker', 'social-worker-moex-100-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '依照「社會團體財務處理辦法」的規定，下列何者不是會計科目？', '["資產", "收入", "基金暨餘絀", "財產登記"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "8a1eb27a2c6e", "answer_pdf_sha1": "fae618103dc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03212', 'social-worker', 'social-worker-moex-100-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '關於「一個非營利組織為某一個人口群提供那些服務，滿足該人口群的那些需求？」是說明該組織的：', '["策略", "使命", "價值", "服務"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "8a1eb27a2c6e", "answer_pdf_sha1": "fae618103dc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03213', 'social-worker', 'social-worker-moex-100-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '彼得杜拉克提醒管理者：「你/妳不可能只僱用一雙手，你/妳僱用的一定是整個人。」這句話與下列那個 陳述中的意思不相關？', '["管理的工作沒有結束的一天", "管理者要尊重員工的差異性", "管理者應鼓勵員工自我管理", "做事的同仁比他所做的事情更重要"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "8a1eb27a2c6e", "answer_pdf_sha1": "fae618103dc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03214', 'social-worker', 'social-worker-moex-100-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '在財務管理中，以量化（如金錢、方案量等）顯示在一個特定時間內某個非營利組織所計畫要進行的活 動，這稱為：', '["編列財務報表", "編列預算", "編列決算", "執行會計"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "8a1eb27a2c6e", "answer_pdf_sha1": "fae618103dc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03215', 'social-worker', 'social-worker-moex-100-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '高社會經濟地位在獲取資訊的方便性通常高於低社會經濟地位者，因此社會工作者運用資訊管理的能力 去教育低社會經濟地位人口群，這樣的努力稱為：', '["建立上網無障礙空間", "縮短數位落差", "倡導網路權益", "建立照顧服務便民入口網站"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "8a1eb27a2c6e", "answer_pdf_sha1": "fae618103dc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03216', 'social-worker', 'social-worker-moex-100-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '在探討非營利組織內部結構時，如果注意到該組織依賴組織規章與程序，如操作手冊、作業程序等來規 範社工員的程度，這是注意到組織那一方面的狀況？', '["正式化（formalization）", "複雜化（complexity）", "集權化（centralization）", "部門化（departmentalization）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "8a1eb27a2c6e", "answer_pdf_sha1": "fae618103dc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03217', 'social-worker', 'social-worker-moex-100-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '在改善績效中有一種積極的思維，鼓勵各組織與利害關係人一起回顧組織的風光年代，並共同思考可以 被期待的未來。透過願景分享，相互合作，此種方法稱為：', '["最佳價值", "肯定式探詢", "學習型組織", "優勢觀點"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "8a1eb27a2c6e", "answer_pdf_sha1": "fae618103dc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03218', 'social-worker', 'social-worker-moex-100-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '在績效考核中，評估者鼓勵員工說出自己對考核過程的意見，而且積極尋求員工關於如何改進考核系統 的意見，這是採取何種考核取向？', '["培力取向（empower approach）", "系統取向（system approach）", "夥伴取向（partnership approach）", "人際互動取向（human interaction approach）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "8a1eb27a2c6e", "answer_pdf_sha1": "fae618103dc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03219', 'social-worker', 'social-worker-moex-100-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '組織所建立的資訊系統涵括所有個案接受方案服務資料，以及各類型服務成果的變項等，並從此資料系 統建立成效指標，回答邁向目標的過程中所遇到的諸多問題，這是屬於何種類型的資訊管理系統？', '["人力資源資訊系統（human resource information system）", "成本導向系統（cost-directed system）", "績效導向系統（performance-directed system）", "行銷募款系統（marketing and fund-raising system）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "8a1eb27a2c6e", "answer_pdf_sha1": "fae618103dc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03220', 'social-worker', 'social-worker-moex-100-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '非營利組織的行銷管理與營利組織有所差異，以下敘述何者為錯誤？', '["非營利組織的產品是指組織所提供的社會服務、理念或實體產品", "非營利組織在行銷時，貨幣價格是產品的主要考量因素", "非營利組織的推廣主要目的是在溝通，而非媒體操作", "非營利組織的服務通路是指輸送社會服務的地理區域、位置或時間"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "8a1eb27a2c6e", "answer_pdf_sha1": "fae618103dc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
